mapper.select:
SELECT ls.LOC_STOCK_ID, ls.PLANT_CD, ls.LOCATION_ID, ls.ITEM_CD, ls.LOT_NO, ls.STOCK_QTY, ls.RESERVED_QTY, ls.AVAILABLE_QTY, ls.REG_USER_ID, ls.REG_DTM, ls.UPD_USER_ID, ls.UPD_DTM, p.PLANT_NM, w.WAREHOUSE_NM, z.ZONE_NM, l.LOCATION_CD, l.LOCATION_NM, i.ITEM_NM, i.ITEM_SPEC, i.UNIT FROM MCS_LOCATION_STOCK ls INNER JOIN MST_PLANT p ON ls.PLANT_CD = p.PLANT_CD INNER JOIN MCS_LOCATION l ON ls.LOCATION_ID = l.LOCATION_ID INNER JOIN MCS_ZONE z ON l.ZONE_ID = z.ZONE_ID INNER JOIN MST_WAREHOUSE w ON z.WAREHOUSE_CD = w.WAREHOUSE_CD INNER JOIN MST_ITEM i ON ls.ITEM_CD = i.ITEM_CD
AND ls.PLANT_CD = #{plantCd} AND w.WAREHOUSE_CD = #{warehouseCd} AND z.ZONE_ID = #{zoneId} AND l.LOCATION_CD LIKE CONCAT('%', #{locationCd}, '%') AND (ls.ITEM_CD LIKE CONCAT('%', #{itemCd}, '%') OR i.ITEM_NM LIKE CONCAT('%', #{itemCd}, '%')) AND ls.LOT_NO LIKE CONCAT('%', #{lotNo}, '%') AND ls.STOCK_QTY > 0
ORDER BY w.WAREHOUSE_CD, z.SORT_SEQ, l.LOCATION_CD, ls.ITEM_CD, ls.LOT_NO LIMIT #{size} OFFSET #{offset}

SELECT h.LOC_TRANS_ID, h.PLANT_CD, h.LOC_STOCK_ID, h.TRANS_TYPE, h.TRANS_QTY, h.BEFORE_QTY, h.AFTER_QTY, h.REF_TYPE, h.REF_NO, h.REF_ID, h.TRANS_RMK, h.REG_USER_ID, h.REG_DTM, p.PLANT_NM, c.COM_NM AS TRANS_TYPE_NM, w.WAREHOUSE_NM, z.ZONE_NM, l.LOCATION_CD, ls.ITEM_CD, i.ITEM_NM, ls.LOT_NO FROM MCS_LOC_TRANS_HIS h INNER JOIN MST_PLANT p ON h.PLANT_CD = p.PLANT_CD INNER JOIN MCS_LOCATION_STOCK ls ON h.LOC_STOCK_ID = ls.LOC_STOCK_ID INNER JOIN MCS_LOCATION l ON ls.LOCATION_ID = l.LOCATION_ID INNER JOIN MCS_ZONE z ON l.ZONE_ID = z.ZONE_ID INNER JOIN MST_WAREHOUSE w ON z.WAREHOUSE_CD = w.WAREHOUSE_CD INNER JOIN MST_ITEM i ON ls.ITEM_CD = i.ITEM_CD LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_INV_TX_TYPE' AND h.TRANS_TYPE = c.COM_CD
AND h.PLANT_CD = #{plantCd} AND h.REG_DTM >= CONCAT(#{fromDate}, ' 00:00:00') AND h.REG_DTM <= CONCAT(#{toDate}, ' 23:59:59') AND h.TRANS_TYPE = #{transType} AND (ls.ITEM_CD LIKE CONCAT('%', #{itemCd}, '%') OR i.ITEM_NM LIKE CONCAT('%', #{itemCd}, '%')) AND l.LOCATION_CD LIKE CONCAT('%', #{locationCd}, '%')
ORDER BY h.REG_DTM DESC, h.LOC_TRANS_ID DESC LIMIT #{size} OFFSET #{offset}
